import sys

class TreeNode:
    def __init__(self, x):
        self.val = x
        self.left = None
        self.right = None

class Solution:
    def preorderTraversal(self, root: TreeNode) -> list[int]:
        res = []
        def pre(root):
            if root:
                res.append(root.val)
                pre(root.left)
                pre(root.right)
        pre(root)
        return res

    def inorderTraversal(self, root: TreeNode) -> list[int]:
        res = []
        def ino(root):
            if root:
                ino(root.left)
                res.append(root.val)
                ino(root.right)
        ino(root)
        return res

    def postorderTraversal(self, root: TreeNode) -> list[int]:
        res = []
        def post(root):
            if root:
                post(root.left)
                post(root.right)
                res.append(root.val)
        post(root)
        return res

if __name__ == '__main__':
    it = iter(sys.stdin.read().split())
    try:
        n = int(next(it))
        vals = [int(next(it)) for _ in range(n)]
        root = TreeNode(vals[0])
        q = [root]
        i = 1
        while q and i < n:
            node = q.pop(0)
            node.left = TreeNode(vals[i]) if i < n else None
            if node.left: q.append(node.left)
            i += 1
            node.right = TreeNode(vals[i]) if i < n else None
            if node.right: q.append(node.right)
            i += 1
        sol = Solution()
        print(' '.join(map(str, sol.preorderTraversal(root))))
        print(' '.join(map(str, sol.inorderTraversal(root))))
        print(' '.join(map(str, sol.postorderTraversal(root))))
    except StopIteration:
        sys.exit(0)

